isDisabled:
{{
  (() => {
    // 1. GLOBAL MANDATORY CHECKS
    // Disables button if any core metadata is missing
    const isGlobalMissing = 
      !selNoteType.selectedOptionValue || 
      !SelectVendor.selectedOptionValue || 
      !dtPckDN.selectedDate || 

      !selDNMode.selectedOptionValue;

    if (isGlobalMissing) return true;

    const mode = selDNMode.selectedOptionValue;
    const lines = appsmith.store.GlobalDebitLinesData || [];

    // 2. FLAT AMOUNT MODE
    // Disables if amount is missing, zero, or negative
    if (mode === "Flat Amount") {
      return !inpDNAmount.text || Number(inpDNAmount.text) <= 0;
    }

    // 3. ITEM RETURN MODE
    // Disables if no items are being returned, or if active returns are missing data
    if (mode === "Item Return") {
      // We only care about rows where the user has entered a Qty
      const rowsToReturn = lines.filter(item => Number(item.Qty) > 0);

      return (
        rowsToReturn.length === 0 || // Disable if no items selected for return
        !rowsToReturn.every(item =>  // Disable if any selected item is missing details
          item["Batch No"]&& 
          item.Reason
        )
      );
    }

    // Default to disabled if mode is somehow unrecognized
    return true; 
  })()
}}
